1	/**
2	 * SIGNAL News Trading Terminal — Frontend Application
3	 * Auto-refreshing financial news aggregator with sentiment analysis
4	 */
5	
6	"use strict";
7	
8	import SignalAuth from './auth.js';
9	
10	// ---------------------------------------------------------------------------
11	// Config
12	// ---------------------------------------------------------------------------
13	
14	const API = "/api";
15	const DEFAULT_LIMIT = 200;
16	const NEW_THRESHOLD_MS = 60000; // 60 seconds
17	const MARKET_REFRESH_MS = 10000; // 10 seconds
18	const MAX_CONCURRENT_FETCHES = 10;
19	
20	// ---------------------------------------------------------------------------
21	// Column Definitions
22	// ---------------------------------------------------------------------------
23	
24	const COLUMN_DEFS = [
25	  { id: 'time', label: 'Time', defaultVisible: true, required: false, requiredFeature: null },
26	  { id: 'sentiment', label: 'Sentiment', defaultVisible: true, required: false, requiredFeature: 'sentiment_filter' },
27	  { id: 'source', label: 'Source', defaultVisible: true, required: false, requiredFeature: null },
28	  { id: 'headline', label: 'Headline', defaultVisible: true, required: true, requiredFeature: null },
29	  { id: 'summary', label: 'Summary', defaultVisible: true, required: false, requiredFeature: null },
30	  { id: 'ticker', label: 'Ticker', defaultVisible: false, required: false, requiredFeature: 'ai_ticker_recommendations' },
31	  { id: 'confidence', label: 'Confidence', defaultVisible: false, required: false, requiredFeature: 'ai_ticker_recommendations' },
32	  { id: 'risk', label: 'Risk Level', defaultVisible: false, required: false, requiredFeature: 'ai_ticker_recommendations' },
33	  { id: 'tradeable', label: 'Tradeable', defaultVisible: false, required: false, requiredFeature: 'ai_ticker_recommendations' },
34	];
35	
36	const LS_COLUMN_KEY = 'instnews_column_visibility';
37	const LS_COLUMN_ORDER_KEY = 'instnews_column_order';
38	const LS_COLUMN_WIDTHS_KEY = 'instnews_column_widths';
39	const MIN_COL_WIDTH = 60;
40	
41	// ---------------------------------------------------------------------------
42	// State
43	// ---------------------------------------------------------------------------
44	
45	let state = {
46	  items: [],
47	  seenIds: new Set(),
48	  newIds: new Set(),
49	  sources: [],
50	  stats: null,
51	  filter: {
52	    sentiment: "all",
53	    sources: new Set(), // empty = all selected
54	    query: "",
55	    dateFrom: "",
56	    dateTo: "",
57	    hideDuplicates: false,
58	  },
59	  refreshInterval: 5000,
60	  refreshTimer: null,
61	  lastRefresh: null,
62	  connected: false,
63	  loading: true,
64	  totalFetched: 0,
65	  fetchCount: 0,
66	  itemsPerSecond: 0,
67	  startTime: Date.now(),
68	  sidebarOpen: false,
69	  modalOpen: false,
70	  detailModalOpen: false,
71	  detailItem: null,
72	  userTier: null,
73	  userFeatures: {},
74	  soundEnabled: false,
75	  columnVisibility: {},
76	  columnOrder: COLUMN_DEFS.map(c => c.id),
77	  columnWidths: {},
78	  columnSettingsOpen: false,
79	  marketPrices: {},
80	  priceRefreshTimer: null,
81	  companyProfileOpen: false,
82	  companyProfileSymbol: null,
83	  companyProfileData: null,
84	  companyProfileLoading: false,
85	  companyProfileActiveTab: "fundamentals",
86	  companyProfileFinancials: null,
87	  companyProfileCompetitors: null,
88	  companyProfileInstitutions: null,
89	  companyProfileInsiders: null,
90	};
91	
92	// ---------------------------------------------------------------------------
93	// DOM References
94	// ---------------------------------------------------------------------------
95	
96	const $ = (sel) => document.querySelector(sel);
97	const $$ = (sel) => [...document.querySelectorAll(sel)];
98	
99	// ---------------------------------------------------------------------------
100	// Utilities
101	// ---------------------------------------------------------------------------
102	
103	function formatTime(dateStr) {
104	  if (!dateStr) return "--:--:--";
105	  try {
106	    const d = new Date(dateStr);
107	    if (isNaN(d.getTime())) return "--:--:--";
108	    return d.toLocaleTimeString("en-US", { hour12: false, hour: "2-digit", minute: "2-digit", second: "2-digit" });
109	  } catch {
110	    return "--:--:--";
111	  }
112	}
113	
114	function formatDate(dateStr) {
115	  if (!dateStr) return "";
116	  try {
117	    const d = new Date(dateStr);
118	    if (isNaN(d.getTime())) return "";
119	    return d.toLocaleDateString("en-US", { month: "short", day: "numeric" });
120	  } catch {
121	    return "";
122	  }
123	}
124	
125	function timeAgo(dateStr) {
126	  if (!dateStr) return "";
127	  try {
128	    const d = new Date(dateStr);
129	    const now = new Date();
130	    const diff = now - d;
131	    if (diff < 0) return "just now";
132	    if (diff < 60000) return `${Math.floor(diff / 1000)}s ago`;
133	    if (diff < 3600000) return `${Math.floor(diff / 60000)}m ago`;
134	    if (diff < 86400000) return `${Math.floor(diff / 3600000)}h ago`;
135	    return `${Math.floor(diff / 86400000)}d ago`;
136	  } catch {
137	    return "";
138	  }
139	}
140	
141	function isNew(dateStr) {
142	  if (!dateStr) return false;
143	  try {
144	    const d = new Date(dateStr);
145	    return (Date.now() - d.getTime()) < NEW_THRESHOLD_MS;
146	  } catch {
147	    return false;
148	  }
149	}
150	
151	function escapeHtml(str) {
152	  const div = document.createElement("div");
153	  div.textContent = str;
154	  return div.innerHTML;
155	}
156	
157	function truncate(str, max) {
158	  if (!str) return "";
159	  return str.length > max ? str.slice(0, max) + "\u2026" : str;
160	}
161	
162	function formatMarketCap(val) {
163	  if (val == null) return "\u2014";
164	  if (val >= 1e12) return "$" + (val / 1e12).toFixed(2) + "T";
165	  if (val >= 1e9) return "$" + (val / 1e9).toFixed(2) + "B";
166	  if (val >= 1e6) return "$" + (val / 1e6).toFixed(2) + "M";
167	  return "$" + val.toLocaleString();
168	}
169	
170	// ---------------------------------------------------------------------------
171	// API Calls
172	// ---------------------------------------------------------------------------
173	
174	async function fetchNews() {
175	  try {
176	    const params = new URLSearchParams({ limit: DEFAULT_LIMIT });
177	    if (state.filter.dateFrom) params.set("from", state.filter.dateFrom);
178	    if (state.filter.dateTo) params.set("to", state.filter.dateTo);
179	    const res = await SignalAuth.fetch(`${API}/news?${params}`);
180	    if (!res.ok) throw new Error(`HTTP ${res.status}`);
181	    const data = await res.json();
182	    state.connected = true;
183	    state.loading = false;
184	    state.fetchCount++;
185	    state.lastRefresh = new Date().toISOString();
186	
187	    if (data.items && data.items.length > 0) {
188	      // Detect new items
189	      const newIds = new Set();
190	      for (const item of data.items) {
191	        if (!state.seenIds.has(item.id)) {
192	          newIds.add(item.id);
193	          state.seenIds.add(item.id);
194	        }
195	      }
196	
197	      // Play sound for new items if enabled
198	      if (state.soundEnabled && newIds.size > 0 && state.fetchCount > 1) {
199	        playNotificationSound();
200	      }
201	
202	      state.newIds = newIds;
203	      state.items = data.items;
204	      state.totalFetched = data.count;
205	
206	      // Calculate items/second
207	      const elapsed = (Date.now() - state.startTime) / 1000;
208	      state.itemsPerSecond = elapsed > 0 ? (state.totalFetched / elapsed).toFixed(1) : 0;
209	    }
210	
211	    renderNews();
212	    updateStatusBar();
213	    updateConnectionStatus(true);
214	    fetchMarketPrices();
215	  } catch (err) {
216	    state.connected = false;
217	    state.loading = false;
218	    updateConnectionStatus(false);
219	    if (state.items.length === 0) {
220	      renderEmpty("Unable to connect to API. Retrying...");
221	    }
222	  }
223	}
224	
225	async function fetchSources() {
226	  try {
227	    const res = await SignalAuth.fetch(`${API}/sources`);
228	    if (!res.ok) return;
229	    const data = await res.json();
230	    state.sources = data.sources || [];
231	    renderSources();
232	  } catch {
233	    // silent
234	  }
235	}
