248	async function fetchMarketPrices() {
249	  if (!state.userFeatures.ai_ticker_recommendations) return;
250	  if (!state.columnVisibility.ticker) return;
251	
252	  const tickers = [...new Set(state.items.map(i => i.target_asset).filter(Boolean))];
253	  if (tickers.length === 0) return;
254	
255	  for (let i = 0; i < tickers.length; i += MAX_CONCURRENT_FETCHES) {
256	    const batch = tickers.slice(i, i + MAX_CONCURRENT_FETCHES);
257	    const promises = batch.map(async (symbol) => {
258	      try {
259	        const res = await SignalAuth.fetch(`${API}/market/${encodeURIComponent(symbol)}`);
